import * as service from '../service/user.service';
import { successResponse } from '../utils/response';
import { asyncHandler } from '../utils/asyncHandler';

export const createUser = asyncHandler(async (req: any, res: any) => {
  const user = await service.createUser(req.body);
  successResponse(res, user);
});

export const getUsers = asyncHandler(async (req: any, res: any) => {
  const users = await service.getUsers();
  successResponse(res, users);
});

import { Request, Response, NextFunction } from 'express';
import { verifyToken } from '../utils/jwt';

export interface AuthRequest extends Request {
  user?: any;
}

export const authMiddleware = (req: AuthRequest, res: Response, next: NextFunction) => {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ message: 'Unauthorized' });
  }

  const decoded = verifyToken(token);

  req.user = decoded;

  next();
};

import { Request, Response, NextFunction } from 'express';
import logger from '../utils/logger';
import { ApiError } from '../utils/appError';
import { ValidationError } from '../errors/customErrors';

export function handleJsonSyntaxError(
  err: SyntaxError,
  req: Request,
  res: Response,
  next: NextFunction,
) {
  if (err instanceof SyntaxError && 'body' in err) {
    const message = 'Invalid JSON format';

    logger.error({
      message,
      stack: err.stack,
      path: req.originalUrl,
      method: req.method,
      statusCode: 400,
    });

    return res.status(400).json({ success: false, message });
  }

  next(err);
}

export function errorHandler(err: Error, req: Request, res: Response, next: NextFunction) {
  let statusCode = 500;
  let message = 'Internal server error';
  let details;

  if (err instanceof ApiError) {
    statusCode = err.statusCode;
    message = err.message;
    if (err instanceof ValidationError) {
      details = err.details;
    }
  }

  logger.error({
    message,
    stack: err.stack,
    path: req.originalUrl,
    method: req.method,
    statusCode,
  });

  return res.status(statusCode).json({ success: false, message, details });
}

import { User } from '../models/user.model';

export const createUser = async (data: any) => {
  return User.create(data);
};

export const findByEmail = async (email: string) => {
  return User.findOne({ where: { email } });
};

export const getAllUsers = async () => {
  return User.findAll();
};

import * as repo from '../repository/user.repository';
import bcrypt from 'bcrypt';
import { AlreadyExistsError } from '../errors/customErrors';

export const createUser = async (data: any) => {
  const existingUser = await repo.findByEmail(data.email);
  if (existingUser) {
    throw new AlreadyExistsError('User with this email already exists');
  }

  data.password = await bcrypt.hash(data.password, 10);
  return repo.createUser(data);
};

export const getUsers = () => repo.getAllUsers();

import jwt from 'jsonwebtoken';
import { ENV } from '../config/env';

export const generateToken = (payload: any) => {
  return jwt.sign(payload, ENV.JWT_SECRET, { expiresIn: '7d' });
};

export const verifyToken = (token: string) => {
  return jwt.verify(token, ENV.JWT_SECRET);
};

export const successResponse = (res: any, data: any, message = 'Success') => {
  return res.status(200).json({
    success: true,
    message,
    data,
  });
};

export const errorResponse = (res: any, message: string, code = 500) => {
  return res.status(code).json({
    success: false,
    message,
  });
};
